export const categories = ["Bullish", "Bearish", "Neutral", "Volatility", "Income", "Hedging", "Complex"];

export const categoryCounts = categories.reduce((acc, cat) => {
  acc[cat] = strategies.filter(s => s.category === cat).length;
  return acc;
}, {});
